package fizeau

import (
	"github.com/easel/fizeau/internal/harnesses"
	claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
	codexharness "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	opencodeharness "github.com/easel/fizeau/internal/harnesses/opencode"
	piharness "github.com/easel/fizeau/internal/harnesses/pi"
)

// harnessInstanceHook, when non-nil, is applied to the default harness map
// before it is returned by defaultHarnessInstances. Tests use this hook to
// substitute fake implementations without modifying service.go or requiring
// a factory parameter on New(). Must be restored after each test (use
// t.Cleanup). Production code must never set this variable.
var harnessInstanceHook func(map[string]harnesses.Harness) map[string]harnesses.Harness

// defaultHarnessInstances returns the production map of registered
// Harness implementations keyed by harness name. Only subprocess
// harnesses with concrete Runner types appear here; embedded
// ("fiz", "virtual", "script") and HTTP-only providers do not own
// quota/account state and are deliberately omitted — the scheduler
// treats absence as "no QuotaHarness/AccountHarness behavior".
//
// This file isolates the per-harness package imports from service.go so
// that service.go can drop them as each harness migrates onto the
// CONTRACT-004 sub-interface surface. The dispatcher in
// internal/serviceimpl/execute_dispatch.go is the only other
// runner-construction seam allowed by CONTRACT-004 invariant #1.
func defaultHarnessInstances() map[string]harnesses.Harness {
	instances := map[string]harnesses.Harness{
		"claude":   &claudeharness.Runner{},
		"codex":    &codexharness.Runner{},
		"gemini":   &geminiharness.Runner{},
		"opencode": &opencodeharness.Runner{},
		"pi":       &piharness.Runner{},
	}
	if harnessInstanceHook != nil {
		instances = harnessInstanceHook(instances)
	}
	return instances
}

package fizeau

import (
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"strings"
	"testing"
)

func TestExecuteDispatcherSeamsAreExplicit(t *testing.T) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "service_execute_dispatch.go", nil, 0)
	if err != nil {
		t.Fatalf("parse service_execute_dispatch.go: %v", err)
	}

	for _, name := range []string{
		"executeRouteResolver",
		"executeSessionLogOpener",
		"executeEventFanout",
		"executeRunnerInvoker",
	} {
		spec := findTypeSpec(file, name)
		if spec == nil {
			t.Fatalf("missing %s seam type", name)
		}
		if _, ok := spec.Type.(*ast.InterfaceType); !ok {
			t.Fatalf("%s is %T, want interface type", name, spec.Type)
		}
	}
}

func TestExecuteDispatcherMovesConcreteRunnerSelectionOutOfExecuteLoop(t *testing.T) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "service_execute.go", nil, 0)
	if err != nil {
		t.Fatalf("parse service_execute.go: %v", err)
	}

	for _, imp := range file.Imports {
		path := imp.Path.Value
		switch path {
		case `"github.com/easel/fizeau/internal/harnesses/claude"`,
			`"github.com/easel/fizeau/internal/harnesses/codex"`,
			`"github.com/easel/fizeau/internal/harnesses/gemini"`,
			`"github.com/easel/fizeau/internal/harnesses/opencode"`,
			`"github.com/easel/fizeau/internal/harnesses/pi"`:
			t.Fatalf("service_execute.go imports concrete runner package %s; selection belongs behind executeRunnerInvoker", path)
		}
	}
}

func TestVirtualAndScriptMechanicsMovedOutOfRootExecute(t *testing.T) {
	data, err := os.ReadFile("service_execute.go")
	if err != nil {
		t.Fatalf("read service_execute.go: %v", err)
	}
	src := string(data)
	for _, implementationDetail := range []string{
		"virtual.response",
		"virtual.dict_dir",
		"script.stdout",
		"script.exit_code",
		"script.delay_ms",
	} {
		if strings.Contains(src, implementationDetail) {
			t.Fatalf("service_execute.go still contains runner implementation detail %q", implementationDetail)
		}
	}
}

func findTypeSpec(file *ast.File, name string) *ast.TypeSpec {
	for _, decl := range file.Decls {
		gen, ok := decl.(*ast.GenDecl)
		if !ok || gen.Tok != token.TYPE {
			continue
		}
		for _, spec := range gen.Specs {
			typeSpec, ok := spec.(*ast.TypeSpec)
			if ok && typeSpec.Name.Name == name {
				return typeSpec
			}
		}
	}
	return nil
}

package serviceimpl

import (
	"context"
	"fmt"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
	codexharness "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	opencodeharness "github.com/easel/fizeau/internal/harnesses/opencode"
	piharness "github.com/easel/fizeau/internal/harnesses/pi"
)

// ExecuteDispatchRequest carries API-neutral data needed to choose the
// concrete execute runner.
type ExecuteDispatchRequest struct {
	Decision ExecuteRunnerDecision
	Started  time.Time
}

// ExecuteDispatchCallbacks connect the internal dispatcher to root-owned
// public event/session adapters.
type ExecuteDispatchCallbacks struct {
	RunNative      func(context.Context)
	RunSubprocess  func(context.Context, harnesses.Harness)
	RunVirtual     func(context.Context)
	RunScript      func(context.Context)
	IsHTTPProvider func(harness string) bool
	Finalize       func(harnesses.FinalData)
}

// DispatchExecuteRun selects the concrete runner for an Execute request.
func DispatchExecuteRun(ctx context.Context, req ExecuteDispatchRequest, cb ExecuteDispatchCallbacks) {
	switch req.Decision.Harness {
	case "fiz", "":
		if cb.RunNative != nil {
			cb.RunNative(ctx)
		}
	case "claude":
		runSubprocess(ctx, cb, &claudeharness.Runner{})
	case "codex":
		runSubprocess(ctx, cb, &codexharness.Runner{})
	case "gemini":
		runSubprocess(ctx, cb, &geminiharness.Runner{})
	case "opencode":
		runSubprocess(ctx, cb, &opencodeharness.Runner{})
	case "pi":
		runSubprocess(ctx, cb, &piharness.Runner{})
	case "virtual":
		if cb.RunVirtual != nil {
			cb.RunVirtual(ctx)
		}
	case "script":
		if cb.RunScript != nil {
			cb.RunScript(ctx)
		}
	default:
		if cb.IsHTTPProvider != nil && cb.IsHTTPProvider(req.Decision.Harness) {
			if cb.RunNative != nil {
				cb.RunNative(ctx)
			}
			return
		}
		finalizeDispatch(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      fmt.Sprintf("harness %q dispatch not yet wired in service.Execute", req.Decision.Harness),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        req.Decision.Harness,
				Provider:       req.Decision.Provider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          req.Decision.Model,
			},
		})
	}
}

func runSubprocess(ctx context.Context, cb ExecuteDispatchCallbacks, runner harnesses.Harness) {
	if cb.RunSubprocess != nil {
		cb.RunSubprocess(ctx, runner)
	}
}

func finalizeDispatch(cb ExecuteDispatchCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

