func TestScanRepositoryAllowsOnlyDocumentedImportSeam(t *testing.T) {
	findings, err := Scan(Options{Root: "../../.."})
	if err != nil {
		t.Fatalf("Scan() error = %v", err)
	}
	if len(findings) != 0 {
		t.Fatalf("unexpected harness import violations: %#v", findings)
	}
}

func TestScanFlagsExternalHarnessImport(t *testing.T) {
	root := t.TempDir()
	writeLintFixture(t, root, "service_feature_branch_probe.go", strings.Join([]string{
		"package fizeau",
		`import claudeharness "github.com/easel/fizeau/internal/harnesses/claude"`,
		"var _ = claudeharness.Runner{}",
	}, "\n")+"\n")

	findings, err := Scan(Options{Root: root})
	if err != nil {
		t.Fatalf("Scan() error = %v", err)
	}
	if len(findings) != 1 {
		t.Fatalf("len(findings) = %d, want 1 (%#v)", len(findings), findings)
	}
	if !strings.Contains(findings[0].Message, contractMessage) {
		t.Fatalf("message = %q, want %q", findings[0].Message, contractMessage)
	}
	if !strings.Contains(findings[0].Message, "internal/serviceimpl/execute_dispatch.go") {
		t.Fatalf("message = %q, want allowed seam hint", findings[0].Message)
	}
}

func TestScanAllowsExecuteDispatchSeam(t *testing.T) {
	root := t.TempDir()
	writeLintFixture(t, root, filepath.Join("internal", "serviceimpl", "execute_dispatch.go"), strings.Join([]string{
		"package serviceimpl",
		`import claudeharness "github.com/easel/fizeau/internal/harnesses/claude"`,
		"var _ = claudeharness.Runner{}",
	}, "\n")+"\n")

	findings, err := Scan(Options{Root: root})
	if err != nil {
		t.Fatalf("Scan() error = %v", err)
	}
	if len(findings) != 0 {
		t.Fatalf("findings = %#v, want none", findings)
	}
}

func writeLintFixture(t *testing.T, root, rel, content string) {
	t.Helper()
	path := filepath.Join(root, rel)
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatalf("MkdirAll(%s): %v", filepath.Dir(path), err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatalf("WriteFile(%s): %v", path, err)
	}
}

package harnessimports

import (
	"fmt"
	"go/parser"
	"go/token"
	"io/fs"
	"path/filepath"
	"slices"
	"sort"
	"strings"
)

const contractMessage = "CONTRACT-004 invariant #1"

var forbiddenImports = []string{
	"github.com/easel/fizeau/internal/harnesses/claude",
	"github.com/easel/fizeau/internal/harnesses/codex",
	"github.com/easel/fizeau/internal/harnesses/gemini",
	"github.com/easel/fizeau/internal/harnesses/opencode",
	"github.com/easel/fizeau/internal/harnesses/pi",
}

type Finding struct {
	Path       string
	Line       int
	Column     int
	ImportPath string
	Message    string
}

type Options struct {
	Root string
}

func Scan(opts Options) ([]Finding, error) {
	root := opts.Root
	if root == "" {
		root = "."
	}

	var findings []Finding
	err := filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			switch d.Name() {
			case ".git", ".claude", ".ddx", "node_modules", "vendor":
				return filepath.SkipDir
			}
			return nil
		}
		if filepath.Ext(path) != ".go" {
			return nil
		}
		rel, err := filepath.Rel(root, path)
		if err != nil {
			return err
		}
		rel = filepath.ToSlash(rel)
		fileFindings, err := scanFile(path, rel)
		if err != nil {
			return err
		}
		findings = append(findings, fileFindings...)
		return nil
	})
	if err != nil {
		return nil, fmt.Errorf("harnessimports: scan %s: %w", root, err)
	}

	sort.Slice(findings, func(i, j int) bool {
		if findings[i].Path != findings[j].Path {
			return findings[i].Path < findings[j].Path
		}
		if findings[i].Line != findings[j].Line {
			return findings[i].Line < findings[j].Line
		}
		return findings[i].Column < findings[j].Column
	})
	return findings, nil
}

func scanFile(path, rel string) ([]Finding, error) {
	if allowedImportSite(rel) {
		return nil, nil
	}

	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, path, nil, parser.ImportsOnly)
	if err != nil {
		return nil, fmt.Errorf("parse %s: %w", rel, err)
	}

	var findings []Finding
	for _, imp := range file.Imports {
		importPath := strings.Trim(imp.Path.Value, `"`)
		if !slices.Contains(forbiddenImports, importPath) {
			continue
		}
		position := fset.Position(imp.Pos())
		findings = append(findings, Finding{
			Path:       rel,
			Line:       position.Line,
			Column:     position.Column,
			ImportPath: importPath,
			Message:    formatMessage(rel, importPath),
		})
	}
	return findings, nil
}

func formatMessage(path, importPath string) string {
	return fmt.Sprintf("%s: %s imports %s; only packages under internal/harnesses/ and internal/serviceimpl/execute_dispatch.go may import concrete per-harness packages", contractMessage, path, importPath)
}

func allowedImportSite(rel string) bool {
	rel = filepath.ToSlash(rel)
	return strings.HasPrefix(rel, "internal/harnesses/") || rel == "internal/serviceimpl/execute_dispatch.go"
}

package builtin

import (
	"github.com/easel/fizeau/internal/harnesses"
	claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
	codexharness "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	opencodeharness "github.com/easel/fizeau/internal/harnesses/opencode"
	piharness "github.com/easel/fizeau/internal/harnesses/pi"
)

// New returns a fresh built-in subprocess harness runner by canonical name.
func New(name string) harnesses.Harness {
	switch name {
	case "claude":
		return &claudeharness.Runner{}
	case "codex":
		return &codexharness.Runner{}
	case "gemini":
		return &geminiharness.Runner{}
	case "opencode":
		return &opencodeharness.Runner{}
	case "pi":
		return &piharness.Runner{}
	default:
		return nil
	}
}

// Instances returns the production map of built-in subprocess harnesses keyed
// by canonical harness name.
func Instances() map[string]harnesses.Harness {
	return map[string]harnesses.Harness{
		"claude":   New("claude"),
		"codex":    New("codex"),
		"gemini":   New("gemini"),
		"opencode": New("opencode"),
		"pi":       New("pi"),
	}
}
